var $bm_rt;
var e, g, n, n, t, v;
e = 0.7;
g = 3000;
$bm_rt = n = 0;
if (numKeys > 0) {
    $bm_rt = n = nearestKey(time).index;
    if (key(n).time > time)
        n--;
}
if (n > 0) {
    $bm_rt = t = $bm_sub(time, key(n).time);
    if (t > 0) {
        v = velocityAtTime($bm_sub(key(n).time, 0.001));
        $bm_rt = $bm_sum(value, [
            0,
            Math.abs(v[1]) * t * e * Math.exp(-4 * t) * Math.sin(8 * t)
        ]);
    } else {
        $bm_rt = value;
    }
} else {
    $bm_rt = value;
}

